using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Secção "Progresso" do Menu de Pausa (Tarefa #11) — mostra o estado geral do
/// jogo (distinto de "Área Atual", que só mostra a fase onde o jogador está).
///
/// Centro: sete fichas (<see cref="worldCards"/>) — uma por mundo + a área
/// final ("Coração de Gaia"). Ao seleccionar um mundo, o painel de detalhe
/// mostra seis linhas, agregadas a partir de <see cref="allAreas"/>/
/// <see cref="allForms"/>/<see cref="allMissions"/> filtradas pelo mundo
/// seleccionado:
///
///   Runas encontradas        34/60
///   Animais libertados        4/5
///   NPCs resgatados          11/18
///   Sussurros entregues       8/21
///   Missões concluídas        6/12
///   Boss regional          Não derrotado
///
/// Os denominadores mostram "?" em vez do total real enquanto
/// <see cref="PlayerProgress.AreWorldTotalsDiscovered"/> for falso para esse
/// mundo (GDD: "Poderia aparecer simplesmente 4/? até o jogador descobrir
/// quantos existem naquele mundo"). Não mostra detalhes secretos nem nomes de
/// animais escondidos — formas "isSecretForm" não entram nesta contagem.
///
/// Parte inferior: nove emblemas (<see cref="allEmblems"/> — Gaia, Apolo, Zeus
/// + um por mundo), via <see cref="EmblemNodeUI"/>, e a percentagem total do
/// save (<see cref="PlayerProgress.GetTotalCompletionPercent"/>). A percentagem
/// é clampada a 100% excepto quando o Emblema de Gaia E o Emblema de Apolo
/// estão ambos obtidos — caso em que mostra exactamente 101% (GDD Tarefa #31).
///
/// Montagem no Editor:
/// - "worldCards": as 7 WorldData (6 mundos + "Coração de Gaia"), por ordem.
/// - "allAreas"/"allForms"/"allMissions"/"allEmblems": todas as ScriptableObjects
///   relevantes do jogo (mesmo padrão de FormsSectionUI/DiarySectionUI).
/// - "worldCardPrefab"/"emblemNodePrefab": prefabs com WorldCardUI/EmblemNodeUI + Button.
/// </summary>
public class ProgressSectionUI : MonoBehaviour, IPauseMenuSection
{
    [Header("Framework")]
    [SerializeField] private GameObject root;

    [Header("Fichas de Mundo (centro)")]
    [Tooltip("As 7 fichas: uma por mundo + a área final (\"Coração de Gaia\"), por ordem de exibição.")]
    [SerializeField] private List<WorldData> worldCards = new List<WorldData>();
    [SerializeField] private Transform worldCardsContainer;
    [SerializeField] private WorldCardUI worldCardPrefab;

    [Header("Listas Globais (para agregação)")]
    [SerializeField] private List<AreaData> allAreas = new List<AreaData>();
    [SerializeField] private List<AnimalFormData> allForms = new List<AnimalFormData>();
    [SerializeField] private List<MissionData> allMissions = new List<MissionData>();
    [SerializeField] private List<EmblemData> allEmblems = new List<EmblemData>();

    [Header("Painel de Detalhe do Mundo")]
    [SerializeField] private GameObject detailRoot;
    [SerializeField] private TMP_Text worldNameText;
    [SerializeField] private TMP_Text runasText;
    [SerializeField] private TMP_Text animalsText;
    [SerializeField] private TMP_Text npcsText;
    [SerializeField] private TMP_Text whispersText;
    [SerializeField] private TMP_Text missionsText;
    [SerializeField] private TMP_Text bossText;

    [Tooltip("Formato para totais já descobertos: {0} = encontrado, {1} = total.")]
    [SerializeField] private string statFormat = "{0}/{1}";

    [Tooltip("Formato para totais ainda não descobertos (PlayerProgress.AreWorldTotalsDiscovered == false): {0} = encontrado.")]
    [SerializeField] private string statUnknownFormat = "{0}/?";

    [SerializeField] private string bossDefeatedText = "Derrotado";
    [SerializeField] private string bossNotDefeatedText = "Não derrotado";

    [Header("Emblemas (parte inferior)")]
    [SerializeField] private Transform emblemsContainer;
    [SerializeField] private EmblemNodeUI emblemNodePrefab;

    [Header("Percentagem Total do Save")]
    [SerializeField] private TMP_Text totalPercentText;

    [Tooltip("Formato da percentagem total: {0} = percentagem (0-100, ou 101 se Gaia+Apolo ambos obtidos — GDD Tarefa #31).")]
    [SerializeField] private string totalPercentFormat = "{0}%";

    private readonly List<GameObject> spawnedWorldCards = new List<GameObject>();
    private readonly List<GameObject> spawnedEmblems = new List<GameObject>();

    public string SectionName => "PROGRESSO";
    public GameObject Root => root != null ? root : gameObject;

    public void Refresh()
    {
        ClearSpawned();

        WorldCardUI firstCard = null;
        WorldData firstWorld = null;

        foreach (var world in worldCards)
        {
            if (world == null || worldCardPrefab == null || worldCardsContainer == null) continue;

            var card = Instantiate(worldCardPrefab, worldCardsContainer);
            card.gameObject.SetActive(true);
            card.Setup(world, ShowWorldDetails);

            spawnedWorldCards.Add(card.gameObject);

            if (firstCard == null)
            {
                firstCard = card;
                firstWorld = world;
            }
        }

        if (firstWorld != null)
        {
            ShowWorldDetails(firstWorld);
            if (EventSystem.current != null) EventSystem.current.SetSelectedGameObject(firstCard.gameObject);
        }
        else if (detailRoot != null)
        {
            detailRoot.SetActive(false);
        }

        RefreshEmblems();
        RefreshTotalPercent();
    }

    public void OnHide()
    {
        // Sem estado próprio a limpar — Refresh() reconstrói tudo na próxima vez.
    }

    // ---------------- Detalhe do Mundo ----------------

    private void ShowWorldDetails(WorldData world)
    {
        if (world == null) return;

        var progress = PlayerProgress.Instance;
        bool discovered = progress != null && progress.AreWorldTotalsDiscovered(world);

        if (detailRoot != null) detailRoot.SetActive(true);
        if (worldNameText != null) worldNameText.text = world.displayName.ToUpperInvariant();

        // Runas encontradas / NPCs resgatados / Sussurros entregues — somados por todas as áreas do mundo.
        int runasFound = 0, runasTotal = 0;
        int npcsFound = 0, npcsTotal = 0;
        int whispersFound = 0, whispersTotal = 0;

        if (progress != null)
        {
            foreach (var area in allAreas)
            {
                if (area == null || area.world != world) continue;

                runasTotal += area.totalRunas;
                runasFound += Mathf.Min(progress.GetRunasFound(area), area.totalRunas);

                npcsTotal += area.totalNpcsToRescue;
                npcsFound += Mathf.Min(progress.GetNpcsRescued(area), area.totalNpcsToRescue);

                whispersTotal += area.totalWhispers;
                whispersFound += Mathf.Min(progress.GetWhispersDelivered(area), area.totalWhispers);
            }
        }

        // Animais libertados — formas não-secretas cuja origem é este mundo.
        int animalsFound = 0, animalsTotal = 0;
        foreach (var form in allForms)
        {
            if (form == null || form.originWorld != world || form.isSecretForm) continue;

            animalsTotal++;
            if (progress != null && progress.HasFreedAnimal(form)) animalsFound++;
        }

        // Missões concluídas — sugeridas para este mundo.
        int missionsFound = 0, missionsTotal = 0;
        var missionManager = MissionManager.Instance;
        foreach (var mission in allMissions)
        {
            if (mission == null || mission.suggestedWorld != world) continue;

            missionsTotal++;
            if (missionManager != null && missionManager.IsMissionCompleted(mission)) missionsFound++;
        }

        if (runasText != null) runasText.text = FormatStat(runasFound, runasTotal, discovered);
        if (animalsText != null) animalsText.text = FormatStat(animalsFound, animalsTotal, discovered);
        if (npcsText != null) npcsText.text = FormatStat(npcsFound, npcsTotal, discovered);
        if (whispersText != null) whispersText.text = FormatStat(whispersFound, whispersTotal, discovered);
        if (missionsText != null) missionsText.text = FormatStat(missionsFound, missionsTotal, discovered);

        if (bossText != null)
        {
            bool defeated = progress != null && progress.HasDefeatedBoss(world);
            bossText.text = defeated ? bossDefeatedText : bossNotDefeatedText;
        }
    }

    private string FormatStat(int found, int total, bool discovered)
    {
        return discovered ? string.Format(statFormat, found, total) : string.Format(statUnknownFormat, found);
    }

    // ---------------- Emblemas ----------------

    private void RefreshEmblems()
    {
        if (emblemNodePrefab == null || emblemsContainer == null) return;

        var vars = GameVariables.Instance;

        foreach (var emblem in allEmblems)
        {
            if (emblem == null) continue;

            bool obtained = vars != null && !string.IsNullOrEmpty(emblem.obtainedVariable) && vars.GetBool(emblem.obtainedVariable);
            bool heardAbout = vars != null && !string.IsNullOrEmpty(emblem.heardAboutVariable) && vars.GetBool(emblem.heardAboutVariable);

            var node = Instantiate(emblemNodePrefab, emblemsContainer);
            node.gameObject.SetActive(true);
            node.Setup(emblem, obtained, heardAbout);

            spawnedEmblems.Add(node.gameObject);
        }
    }

    // ---------------- Percentagem Total ----------------

    private void RefreshTotalPercent()
    {
        if (totalPercentText == null) return;

        var progress = PlayerProgress.Instance;
        int percent = progress != null ? progress.GetTotalCompletionPercent(allAreas, allForms, allMissions, allEmblems) : 0;

        totalPercentText.text = string.Format(totalPercentFormat, percent);
    }

    // ---------------- Limpeza ----------------

    private void ClearSpawned()
    {
        foreach (var go in spawnedWorldCards)
            if (go != null) Destroy(go);
        spawnedWorldCards.Clear();

        foreach (var go in spawnedEmblems)
            if (go != null) Destroy(go);
        spawnedEmblems.Clear();
    }
}

/// <summary>
/// Ficha de um mundo (ou da área final "Coração de Gaia") na secção Progresso.
/// Mostra apenas o nome do mundo — ao seleccionar, o painel de detalhe é
/// actualizado via <see cref="Setup"/>'s callback.
/// </summary>
public class WorldCardUI : MonoBehaviour, ISelectHandler
{
    [SerializeField] private TMP_Text nameText;
    [SerializeField] private Image iconImage;

    private WorldData world;
    private System.Action<WorldData> onSelected;

    public void Setup(WorldData world, System.Action<WorldData> onSelected)
    {
        this.world = world;
        this.onSelected = onSelected;

        if (nameText != null) nameText.text = world.displayName;
    }

    public void OnSelect(BaseEventData eventData)
    {
        onSelected?.Invoke(world);
    }
}

/// <summary>
/// Nó de um emblema (Gaia/Apolo/Zeus ou de mundo) na parte inferior da secção
/// Progresso.
///
/// Estados:
/// - Obtido: mostra <see cref="EmblemData.icon"/> e o nome.
/// - Não obtido, mas já "ouvido falar": mostra <see cref="EmblemData.unknownIcon"/>
///   ("marca de pedra desconhecida") e a <see cref="EmblemData.conditionDescription"/>.
/// - Não obtido e ainda não "ouvido falar": mostra apenas
///   <see cref="EmblemData.unknownIcon"/>, sem nome nem condição.
/// </summary>
public class EmblemNodeUI : MonoBehaviour, ISelectHandler
{
    [SerializeField] private Image iconImage;
    [SerializeField] private TMP_Text nameText;

    [Header("Detalhe (ao seleccionar)")]
    [SerializeField] private GameObject detailRoot;
    [SerializeField] private TMP_Text detailNameText;
    [SerializeField] private TMP_Text detailConditionText;

    [SerializeField] private string unknownName = "???";

    private EmblemData emblem;
    private bool obtained;
    private bool heardAbout;

    public void Setup(EmblemData emblem, bool obtained, bool heardAbout)
    {
        this.emblem = emblem;
        this.obtained = obtained;
        this.heardAbout = heardAbout;

        if (iconImage != null)
        {
            iconImage.sprite = obtained ? emblem.icon : emblem.unknownIcon;
            iconImage.enabled = iconImage.sprite != null;
        }

        if (nameText != null) nameText.text = obtained ? emblem.displayName : unknownName;
    }

    public void OnSelect(BaseEventData eventData)
    {
        if (detailRoot == null) return;

        if (obtained)
        {
            detailRoot.SetActive(true);
            if (detailNameText != null) detailNameText.text = emblem.displayName;
            if (detailConditionText != null) detailConditionText.text = string.Empty;
        }
        else if (heardAbout)
        {
            detailRoot.SetActive(true);
            if (detailNameText != null) detailNameText.text = unknownName;
            if (detailConditionText != null) detailConditionText.text = emblem.conditionDescription;
        }
        else
        {
            detailRoot.SetActive(false);
        }
    }
}
